// Nichos a investigar
var nichos = [
  {nicho: "restaurantes", keywords: "problemas whatsapp, clientes que no reservan, facturacion lenta"},
  {nicho: "gimnasios", keywords: "membresias que se vencen, alumnos que abandonan, cobros automaticos"},
  {nicho: "abogados", keywords: "seguimiento de casos, clientes que no pagan, reuniones perdidas"},
  {nicho: "contadores", keywords: "facturas atrasadas, clientes morosos, declaraciones tardias"},
  {nicho: "clinicas medicas", keywords: "citas que no asisten, recordatorios, cobros seguros"},
  {nicho: "agencias de marketing", keywords: "leads que se enfrían, clientes sin seguimiento, reportes"},
  {nicho: "tiendas online", keywords: "carritos abandonados, respuestas lentas, inventario desactualizado"},
  {nicho: "bienes raices", keywords: "prospectos que desaparecen, visitas perdidas, seguimiento lento"},
  {nicho: "consultorios dentales", keywords: "citas canceladas, presupuestos sin responder, rappel de tratamiento"},
  {nicho: "autolavados", keywords: "citas que no llegan, clientes nuevos que no regresan, promociones"}
];

// Seleccionar 1 nicho aleatorio
var nicho = nichos[Math.floor(Math.random() * nichos.length)];

return [{json: nicho}];

// Extraer respuesta del AI Agent
var raw = $input.first().json;
var content = raw.output?.parameters?.jsCode || raw.text || raw.content || JSON.stringify(raw);
var data = {};

// Limpiar markdown si existe
content = content.replace(/```json\n?/gi, '').replace(/```\n?/gi, '').trim();

// Combinar con datos del nicho original
var nichoOriginal = $('Seleccionar Nicho').first().json;

try {
  data = JSON.parse(content);
} catch(e) {
  data.nicho = nichoOriginal.nicho || '';
  data.tema = 'Contenido SST';
  data.caption = content;
  data.promptImagen = 'modern business office team working together';
  data.dolor = '';
}

// Asegurar que tenemos el nicho
if (!data.nicho) data.nicho = nichoOriginal.nicho;

return [{
  json: {
    nicho: data.nicho || '',
    dolor: data.dolor || '',
    tema: data.tema || 'Post SST',
    caption: data.caption || '',
    promptImagen: data.promptImagen || 'modern business office'
  }
}];

var imagenData = $input.first();
var contenido = $('Preparar Contenido1').first().json;
return [{
  json: contenido,
  binary: {
    data: imagenData.binary.data
  }
}];

